const { Client } = require('@openai/node-sdk');
const { exec } = require('child_process');

// Initialize OpenAI client
const openai = new Client({ apiKey: 'your-openai-api-key' });

// Define the route for code generation and execution
app.post('/generate-and-execute', async (req, res) => {
  try {
    const { description } = req.body;

    // Send prompt to AI model
    const response = await openai.chat.completions.create({
      messages: [{ role: 'user', content: description }],
      model: 'gpt-3.5-turbo',
    });

    const generatedCode = response.choices[0].message.content.trim();

    // Execute the generated code
    try {
      exec(generatedCode, (error, stdout, stderr) => {
        if (error) {
          return res.status(500).json({ error: `Error executing code: ${stderr}` });
        }
        res.json({ output: stdout });
      });
    } catch (error) {
      res.status(500).json({ error: `Error executing code: ${error.message}` });
    }
  } catch (error) {
    res.status(500).json({ error: `Error generating code: ${error.message}` });
  }
});

// Start the server
app.listen(3000, () => {
  console.log('Server is running on port 3000');
});